mapper.select:
SELECT id, interface_id, adapter_type, url, http_method, timeout_ms, auth_type, auth_value, request_headers, datasource_id, statement_id, operation_type, remote_host, remote_port, remote_user, remote_password, remote_path, done_path, file_pattern, file_encoding, extra_config, is_active, created_at, updated_at FROM eai_adapter_config
AND interface_id = #{interfaceId}
ORDER BY id
